mapper.select:
/* OptionMgmtQueryRepository.getOptionCategoryList */ SELECT TA.OPTN_CAT_NO , TA.OPTN_CAT_REG_GB_CD , FN_GET_CODENAME('PR018', TA.OPTN_CAT_REG_GB_CD) AS OPTN_CAT_REG_GB_CD_NM , TA.ENTR_NO , TB.ENTR_NM , TA.OPTN_CAT_TYP_CD , FN_GET_CODENAME('PR019', TA.OPTN_CAT_TYP_CD) AS OPTN_CAT_TYP_CD_NM , TC.OPTN_CAT_NM , TC.LANG_CD , TA.SORT_SEQ , TA.USE_YN , TA.SYS_MOD_ID , TA.SYS_MOD_DTM , TA.SYS_REG_ID , TA.SYS_REG_DTM , COUNT(1) OVER() AS TOTAL_COUNT FROM PR_OPTN_CLSS_CD TA LEFT JOIN ET_ENTR_BASE TB ON TA.ENTR_NO = TB.ENTR_NO JOIN PR_OPTN_CLSS_CD_ML TC ON TA.OPTN_CAT_NO = TC.OPTN_CAT_NO
AND TC.LANG_CD = #{langCd}
AND TC.LANG_CD = 'ko'
WHERE 1=1
AND TA.USE_YN = #{condxUseYn}
AND TA.OPTN_CAT_TYP_CD = #{condxOptnCatTypCd}
AND TA.OPTN_CAT_REG_GB_CD = #{condxOptnCatRegGbCd}
AND (TA.ENTR_NO = #{entrNo} OR TA.OPTN_CAT_REG_GB_CD = '01')
AND TA.OPTN_CAT_NO = #{optnCatNo}
ORDER BY TA.SORT_SEQ, TA.SYS_MOD_DTM DESC

/* OptionMgmtQueryRepository.getPrOptnCdList */ SELECT TA.OPTN_CAT_NO , TA.OPTN_NO , TB.OPTN_NM , TB.LANG_CD , TA.SORT_SEQ , TA.USE_YN , TA.IMG_PATH_NM , TA.IMG_FILE_NM , TA.RGB_VAL , TA.SYS_MOD_ID , TA.SYS_MOD_DTM , TA.SYS_REG_ID , TA.SYS_REG_DTM , COUNT(1) OVER() AS TOTAL_COUNT FROM PR_OPTN_CD TA JOIN PR_OPTN_CD_ML TB ON TA.OPTN_CAT_NO = TB.OPTN_CAT_NO AND TA.OPTN_NO = TB.OPTN_NO
AND TB.LANG_CD = #{langCd}
AND TB.LANG_CD = 'ko'
WHERE TA.OPTN_CAT_NO = #{optnCatNo}
AND TA.USE_YN = #{useYn}
ORDER BY TA.SORT_SEQ, TA.SYS_MOD_DTM DESC
